import java.io.IOException;
import java.io.PrintWriter;
import javax.servlet.http.HttpServlet;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;

public class XSSSafeServlet extends HttpServlet {

    protected void doPost(HttpServletRequest request, HttpServletResponse response) throws IOException {
        String userInput = request.getParameter("input");

        // Sanitize and encode user input to prevent XSS
        String safeUserInput = sanitizeUserInput(userInput);

        // Properly handle user input with encoding
        String output = "<p>User input: " + safeUserInput + "</p>";

        response.setContentType("text/html");
        PrintWriter out = response.getWriter();
        out.println(output);
    }

    private String sanitizeUserInput(String userInput) {
        // Implement proper input sanitization by encoding special characters
        return userInput
            .replace("&", "&amp;")
            .replace("<", "&lt;")
            .replace(">", "&gt;")
            .replace("\"", "&quot;")
            .replace("'", "&#39;");
    }
}

